export const meta = {
  name: 'deep-codebase-exploration',
  description: '深度探索 OpenCoreAnalysisKit 代码仓库并结构化知识沉淀',
  phases: [
    { title: '项目结构扫描', detail: '扫描目录结构、文件清单和技术栈' },
    { title: '核心模块分析', detail: '并行分析 parser、android、command 等核心模块' },
    { title: '架构与依赖提取', detail: '提取架构层次、依赖关系和数据流' },
    { title: '知识文档生成', detail: '生成结构化知识文档和 Mermaid 架构图' },
    { title: '知识验证', detail: '验证生成的知识文档完整性' }
  ]
}

// Phase 1: 项目结构扫描
phase('项目结构扫描')
log('开始扫描项目结构...')

const projectStructureSchema = {
  type: 'object',
  properties: {
    directory_tree: { type: 'object', description: '目录树结构' },
    file_count: { type: 'object', description: '各类型文件数量统计' },
    key_directories: { type: 'array', items: { type: 'string' }, description: '关键目录列表' },
    tech_stack: { type: 'object', description: '技术栈信息' },
    build_system: { type: 'string', description: '构建系统' },
    dependencies: { type: 'array', description: '外部依赖列表' }
  },
  required: ['directory_tree', 'file_count', 'key_directories', 'tech_stack']
}

const projectStructure = await agent(
  `扫描 /home/cwtrocks/OpenCoreAnalysisKit 目录结构，统计文件类型，识别关键目录（parser/、android/、command/ 等），分析技术栈（C++版本、构建系统、依赖库）。返回完整的项目结构概览。`,
  { 
    label: '扫描项目结构', 
    schema: projectStructureSchema,
    agentType: 'understand-anything:project-scanner'
  }
)

log(`项目结构扫描完成：发现 ${projectStructure?.key_directories?.length || 0} 个关键目录`)

// Phase 2: 核心模块并行分析
phase('核心模块分析')
log('并行分析核心模块...')

const moduleAnalysisSchema = {
  type: 'object',
  properties: {
    module_name: { type: 'string' },
    purpose: { type: 'string', description: '模块用途' },
    key_files: { type: 'array', items: { type: 'string' }, description: '关键文件列表' },
    key_classes: { type: 'array', description: '关键类和函数' },
    responsibilities: { type: 'array', items: { type: 'string' }, description: '职责列表' },
    dependencies: { type: 'array', items: { type: 'string' }, description: '依赖的其他模块' },
    interfaces: { type: 'array', description: '对外接口' }
  },
  required: ['module_name', 'purpose', 'key_files', 'responsibilities']
}

const modules = [
  { name: 'parser', path: 'parser/', desc: '主程序入口和命令系统' },
  { name: 'android', path: 'android/', desc: 'Android ART 运行时镜像' },
  { name: 'command', path: 'parser/command/', desc: 'REPL 命令实现' },
  { name: 'daemon', path: 'parser/daemon/', desc: 'HTTP 和 MCP 服务器' },
  { name: 'art-runtime', path: 'android/art/runtime/', desc: 'ART 运行时对象模型' },
  { name: 'dex', path: 'android/art/dex/', desc: 'DEX 文件格式解析' }
]

const moduleAnalyses = await pipeline(
  modules,
  async (module) => {
    return await agent(
      `深度分析模块 ${module.name}（路径: ${module.path}）。识别关键文件、类、函数，理解模块职责和对外接口。返回详细的模块分析。描述: ${module.desc}`,
      {
        label: `分析 ${module.name}`,
        schema: moduleAnalysisSchema,
        phase: '核心模块分析'
      }
    )
  }
)

log(`模块分析完成：成功分析 ${moduleAnalyses.filter(Boolean).length}/${modules.length} 个模块`)

// Phase 3: 架构与依赖提取
phase('架构与依赖提取')
log('提取系统架构和依赖关系...')

const architectureSchema = {
  type: 'object',
  properties: {
    layers: { type: 'array', description: '架构层次' },
    module_dependencies: { type: 'object', description: '模块依赖关系图' },
    data_flow: { type: 'array', description: '核心数据流路径' },
    entry_points: { type: 'array', items: { type: 'string' }, description: '程序入口点' },
    key_patterns: { type: 'array', items: { type: 'string' }, description: '关键设计模式' }
  },
  required: ['layers', 'module_dependencies', 'entry_points']
}

const architecture = await agent(
  `基于项目结构和模块分析结果，提取 OpenCoreAnalysisKit 的整体架构：
  1. 识别架构层次（CLI层、命令层、运行时镜像层、核心解析层）
  2. 绘制模块依赖关系
  3. 追踪核心数据流（从 coredump 加载到对象查询）
  4. 识别程序入口点和关键设计模式

  项目概述：C++ 工具，用于分析 Android coredumps，包含命令系统、ART 运行时镜像、DEX 解析等。`,
  {
    label: '提取架构',
    schema: architectureSchema,
    agentType: 'understand-anything:architecture-analyzer'
  }
)

log(`架构提取完成：识别 ${architecture?.layers?.length || 0} 个架构层`)

// Phase 4: 知识文档生成
phase('知识文档生成')
log('生成结构化知识文档...')

const docGenerationSchema = {
  type: 'object',
  properties: {
    markdown_content: { type: 'string', description: '完整的 Markdown 文档内容' },
    mermaid_diagrams: { type: 'array', description: 'Mermaid 图表定义' },
    key_insights: { type: 'array', items: { type: 'string' }, description: '关键洞察' },
    file_path: { type: 'string', description: '建议保存的文件路径' }
  },
  required: ['markdown_content', 'key_insights']
}

const knowledgeDoc = await agent(
  `基于以下信息生成完整的知识文档：

  项目结构: ${JSON.stringify(projectStructure, null, 2)}
  模块分析: ${JSON.stringify(moduleAnalyses.filter(Boolean), null, 2)}
  架构信息: ${JSON.stringify(architecture, null, 2)}

  生成内容应包括：
  1. 项目总览（技术栈、目标、特性）
  2. 架构设计（层次结构、模块关系）
  3. 核心模块详解（每个模块的职责、关键类、接口）
  4. 数据流和执行流程
  5. 关键设计决策和模式
  6. 开发指南（如何添加新命令、如何扩展）
  7. Mermaid 架构图（系统架构图、模块依赖图、数据流图）

  文档应保存到 docs/architecture-knowledge.md`,
  {
    label: '生成知识文档',
    schema: docGenerationSchema
  }
)

log(`知识文档生成完成，建议保存路径: ${knowledgeDoc?.file_path || 'docs/architecture-knowledge.md'}`)

// 保存知识文档
if (knowledgeDoc?.markdown_content) {
  const saveResult = await agent(
    `将以下 Markdown 内容保存到文件 ${knowledgeDoc.file_path || 'docs/architecture-knowledge.md'}:

    ${knowledgeDoc.markdown_content}

    确保 docs/ 目录存在，如果不存在则创建。`,
    { label: '保存知识文档', phase: '知识文档生成' }
  )
  log('知识文档已保存到文件系统')
}

// 生成 Mermaid 图表
if (knowledgeDoc?.mermaid_diagrams && knowledgeDoc.mermaid_diagrams.length > 0) {
  const diagramResults = await parallel(
    knowledgeDoc.mermaid_diagrams.map((diagram, idx) => async () => {
      return await agent(
        `使用 mcp__mermaid__mermaid_preview 工具生成 Mermaid 图表预览：

        图表定义: ${JSON.stringify(diagram)}
        preview_id: architecture-diagram-${idx}

        生成预览并返回预览 URL。`,
        { 
          label: `生成图表 ${idx + 1}`,
          phase: '知识文档生成'
        }
      )
    })
  )
  log(`生成了 ${diagramResults.filter(Boolean).length} 个架构图表`)
}

// Phase 5: 知识验证
phase('知识验证')
log('验证知识文档完整性...')

const validationSchema = {
  type: 'object',
  properties: {
    completeness_score: { type: 'number', description: '完整性评分 0-100' },
    missing_areas: { type: 'array', items: { type: 'string' }, description: '缺失的知识领域' },
    recommendations: { type: 'array', items: { type: 'string' }, description: '改进建议' },
    is_valid: { type: 'boolean', description: '是否通过验证' }
  },
  required: ['completeness_score', 'is_valid']
}

const validation = await agent(
  `验证生成的知识文档完整性：

  1. 检查是否覆盖了所有核心模块
  2. 检查架构图是否清晰表达了系统结构
  3. 检查是否包含足够的代码示例和说明
  4. 检查文档是否易于理解和查阅
  5. 评估文档对新开发者的帮助程度

  生成的文档路径: ${knowledgeDoc?.file_path || 'docs/architecture-knowledge.md'}
  关键洞察数量: ${knowledgeDoc?.key_insights?.length || 0}
  模块覆盖数: ${moduleAnalyses.filter(Boolean).length}`,
  {
    label: '验证知识文档',
    schema: validationSchema
  }
)

log(`验证完成：完整性评分 ${validation?.completeness_score || 0}/100`)

// 返回最终结果
return {
  status: 'completed',
  project_structure: projectStructure,
  modules_analyzed: moduleAnalyses.filter(Boolean).length,
  architecture: architecture,
  knowledge_doc_path: knowledgeDoc?.file_path,
  validation: validation,
  summary: {
    total_modules: modules.length,
    analyzed_modules: moduleAnalyses.filter(Boolean).length,
    architecture_layers: architecture?.layers?.length || 0,
    key_insights: knowledgeDoc?.key_insights?.length || 0,
    completeness_score: validation?.completeness_score || 0,
    is_valid: validation?.is_valid || false
  }
}
